<script>
(() => {
  const statusUrl = 'https://testingcf.jsdelivr.net/gh/linlangliehu/tavern_helper_template@d3e9143d4ee72bd9ce4e9cdf6d579bcd0ee5fc7e/dist/%E7%A5%9E%E7%A7%98%E5%A4%8D%E8%8B%8F%E6%A8%A1%E6%8B%9F%E5%99%A8/%E7%95%8C%E9%9D%A2/%E7%8A%B6%E6%80%81%E6%A0%8F/index.html?v=phase103-mobile-options-fix-2-0';
  const doc = window.parent?.document || document;
  const hostId = 'mfrs-fixed-status-host';
  const frameId = 'mfrs-fixed-status-frame';

  const mount = () => {
    const sendForm = doc.querySelector('#send_form') || doc.querySelector('#form_sheld');
    if (!sendForm) return false;

    let host = doc.querySelector(`#${hostId}`);
    if (!host) {
      host = doc.createElement('div');
      host.id = hostId;
      host.style.width = '100%';
      host.style.maxHeight = '42vh';
      host.style.overflow = 'hidden auto';
      host.style.margin = '0 auto 8px';
      host.style.border = '1px solid rgba(90, 18, 18, 0.65)';
      host.style.borderRadius = '8px';
      host.style.background = 'rgba(5, 2, 2, 0.96)';
      host.style.boxShadow = '0 0 18px rgba(0, 0, 0, 0.65)';
      sendForm.parentElement?.insertBefore(host, sendForm);
    }

    let frame = doc.querySelector(`#${frameId}`);
    if (!frame) {
      frame = doc.createElement('iframe');
      frame.id = frameId;
      frame.title = '神秘复苏固定状态栏';
      frame.style.display = 'block';
      frame.style.width = '100%';
      frame.style.height = '360px';
      frame.style.border = '0';
      frame.style.background = 'transparent';
      host.replaceChildren(frame);
    }
    frame.src = `${statusUrl}?t=${Date.now()}`;
    return true;
  };

  const retry = (attempt = 1) => {
    if (mount()) return;
    if (attempt < 20) setTimeout(() => retry(attempt + 1), 500);
  };

  retry();
})();
</script>
